#include <stdio.h>
#include <unistd.h>
#include <sys/wait.h>

int main(void) {
    setbuf(stdout, NULL);
    printf("Before exec\n");

    pid_t child = fork();
    if (child == -1) { perror("fork"); return 1; }

    if (child == 0) {
        /* L'enfant lance echo */
        char *argv[] = {"echo", "Hello from exec!", NULL};
        execvp("echo", argv);
        /* Si on arrive ici, exec a echoue */
        perror("execvp");
        _exit(1);
    }

    int status;
    waitpid(child, &status, 0);
    if (WIFEXITED(status))
        printf("Child exited: %d\n", WEXITSTATUS(status));

    printf("Parent continues\n");
    return 0;
}

